// Cal.com Webhook HMAC-SHA256 Signature Verification
const crypto = require('crypto');

const SIGNING_SECRET = 'crl-webhook-2026-8jUnu28SNS*n8@82';

const signature = $input.first().json.headers['x-cal-signature-256'];

// Get raw body from binary data or stringify the body
let rawBody;
if ($input.first().binary && $input.first().binary.data && $input.first().binary.data.data) {
  rawBody = Buffer.from($input.first().binary.data.data, 'base64').toString('utf8');
} else {
  rawBody = JSON.stringify($input.first().json.body);
}

if (!signature) {
  return [{ json: { signatureValid: false, error: 'Missing X-Cal-Signature-256 header' } }];
}

if (!rawBody) {
  return [{ json: { signatureValid: false, error: 'Missing request body' } }];
}

// Compute expected HMAC-SHA256 signature
const expectedSignature = crypto
  .createHmac('sha256', SIGNING_SECRET)
  .update(rawBody)
  .digest('hex');

// Compare signatures
if (signature === expectedSignature) {
  return [{ json: { ...$input.first().json, signatureValid: true } }];
} else {
  return [{ json: { signatureValid: false, error: 'Signature mismatch' } }];
}

